import psycopg2
from psycopg2 import sql
import sys

def install_extension(connection_params, extension_name):
    try:
        # Establish connection
        conn = psycopg2.connect(**connection_params)
        cursor = conn.cursor()
        
        # Validate extension name to prevent injection
        if not extension_name.replace('_', '').replace('-', '').isalnum():
            raise ValueError("Invalid extension name")
        
        # Use sql.Identifier for safe identifier handling
        safe_extension_name = sql.Identifier(extension_name)
        
        # Check if extension already exists
        cursor.execute("""
            SELECT 1 FROM pg_extension WHERE extname = %s
        """, (extension_name,))
        
        if cursor.fetchone():
            print(f"Extension {extension_name} already exists")
            return True
        
        # Create extension safely
        create_query = sql.SQL("CREATE EXTENSION IF NOT EXISTS {}").format(safe_extension_name)
        cursor.execute(create_query)
        
        conn.commit()
        print(f"Extension {extension_name} installed successfully")
        return True
        
    except psycopg2.Error as e:
        print(f"Database error: {e}")
        return False
    except ValueError as e:
        print(f"Validation error: {e}")
        return False
    except Exception as e:
        print(f"Unexpected error: {e}")
        return False
    finally:
        if 'cursor' in locals():
            cursor.close()
        if 'conn' in locals():
            conn.close()

